    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

class Solution {
    int maxSum = 0;

    public int maxSumBST(TreeNode root) {
        dfs(root);
        return maxSum;
    }

    private int[] dfs(TreeNode node) {
        if (node == null) 
            return new int[]{1, 0, Integer.MAX_VALUE, Integer.MIN_VALUE};

        int[] l = dfs(node.left);
        int[] r = dfs(node.right);

        if (l[0] == 0 || r[0] == 0 || node.val <= l[3] || node.val >= r[2]) 
            return new int[4];

